import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { apiFetch } from './services/api';
import { useAuth } from './context/AuthContext';

export default function UploadArticle(){
    const [name, setName] = useState('');
    const [file, setFile] = useState(null);
    const [slug, setSlug] = useState('');
    const [msg, setMsg] = useState('');
    const [sections, setSections] = useState([]);
    const [fkSection, setFkSection] = useState('');
    const navigate = useNavigate();
    const { user, loading } = useAuth();

    useEffect(() => {
        if (!loading && !user) navigate('/login');
    }, [loading, user, navigate]);

    useEffect(()=>{
        (async ()=>{
            try{
                const { res, data } = await apiFetch('/api/sections');
                if(res.ok && data && data.data) setSections(data.data);
            }catch(e){/* ignore */}
        })();
    }, []);

    function handleSubmit(e){
        e.preventDefault();
        /*if(!file && !slug){
            setMsg('Seleccione un archivo o indique un slug+markdown.');
            return;
        }*/

        const form = new FormData();
        if(file) form.append('file', file);
        if(fkSection) form.append('fk_section', fkSection);
        else {
            // if no file, try to use a textarea? keep minimal: require file
            setMsg('Por ahora sube un .md como archivo.');
            return;
        }

        (async ()=>{
            try{
                const { res, data } = await apiFetch('/api/content/add', { method: 'POST', body: form });
                if(res.ok) setMsg('Artículo subido. ' + (data && data.data && data.data.slug ? data.data.slug : 'ok'));
                else setMsg('Error: ' + JSON.stringify(data || await res.text()));
            }catch(e){ setMsg('Error: ' + e.message); }
        })();
    }

    return (
        <div className="w-1/2 m-auto">
            <h2>Subir artículo (.md)</h2>
            <form onSubmit={handleSubmit}>
                <div>
                    <label>
                        <input type="text" onChange={e=>setFile(e.target.value)} />
                    </label>
                </div>
                <div>
                    <label>Archivo .md
                        <input type="file" accept=".md,text/markdown" onChange={e=>setFile(e.target.files[0])} />
                    </label>
                </div>
                <div>
                    <label>Sección
                        <select value={fkSection} onChange={e=>setFkSection(e.target.value)}>
                            <option value="">(ninguna)</option>
                            {sections.map(s=> <option key={s.pk_section} value={s.pk_section}>{s.name}</option>)}
                        </select>
                    </label>
                </div>
                <div className="mt-2">
                    <button className="bg-teal-950 text-white p-2 rounded" type="submit">Subir</button>
                </div>
            </form>
            <p>{msg}</p>
        </div>
    );
}
